import{_ as o,C as n,o as e,c as l,ah as s,b as r,w as i,a as E,E as d,ai as p}from"./chunks/framework.BM5zFche.js";const h="/images/mcp-design-flow.png",q=JSON.parse('{"title":"MCP 简介与工具调用流程","description":"了解 Model Context Protocol 的 Host、Client、Server 架构，以及 MCP 工具发现和调用的完整过程。","frontmatter":{"title":"MCP 简介与工具调用流程","description":"了解 Model Context Protocol 的 Host、Client、Server 架构，以及 MCP 工具发现和调用的完整过程。"},"headers":[],"relativePath":"ai/mcp.md","filePath":"ai/mcp.md","lastUpdated":1784602594000}'),c={name:"ai/mcp.md"};function A(k,t,C,B,u,g){const a=n("Mermaid");return e(),l("div",null,[t[1]||(t[1]=s('<h1 id="mcp-简介与工具调用流程" tabindex="-1">MCP 简介与工具调用流程 <a class="header-anchor" href="#mcp-简介与工具调用流程" aria-label="Permalink to &quot;MCP 简介与工具调用流程&quot;">​</a></h1><p>MCP（Model Context Protocol，模型上下文协议）是一套让 AI 应用以统一方式连接外部能力的开放协议。它把文件、数据库、GitHub、IDE、企业系统等能力封装成标准接口，使不同 AI 应用可以按需发现、调用和组合这些能力。</p><p>可以把 MCP 理解为 AI 应用与外部系统之间的“通用插座”：AI 应用不必为每个系统单独设计一套接入方式，而是通过 MCP Client 与相应的 MCP Server 通信。</p><p><img src="'+h+'" alt="MCP Host / Client / Server 架构与工具调用流程"></p><h2 id="核心角色" tabindex="-1">核心角色 <a class="header-anchor" href="#核心角色" aria-label="Permalink to &quot;核心角色&quot;">​</a></h2><p>MCP 采用 Host / Client / Server 架构。一个 Host 可以管理多个 Client；每个 Client 通常与一个 Server 维持一条相互隔离的连接。</p><table tabindex="0"><thead><tr><th>角色</th><th>职责</th><th>示例</th></tr></thead><tbody><tr><td>Host</td><td>承载 AI 会话，管理上下文、权限、用户确认与 Client 生命周期，并将工具结果交给 LLM 使用</td><td>Codex、Claude Code、Cursor、IDE、Agent 应用</td></tr><tr><td>MCP Client</td><td>由 Host 创建，负责与某个 Server 协商协议、收发消息和维护会话</td><td>Host 内部的 MCP 连接实例</td></tr><tr><td>MCP Server</td><td>对外提供专一能力，执行真实操作并返回结果</td><td>文件系统、GitHub、数据库、IDE 索引服务</td></tr><tr><td>LLM</td><td>根据用户问题和 Host 提供的工具说明，决定是否调用工具以及如何组织答案</td><td>GPT、Claude 等模型</td></tr></tbody></table><p>关键边界是：<strong>Host 管理会话、权限与用户授权；Server 只暴露自己负责的能力。</strong> Server 不应默认获得完整对话历史，也不应直接访问其他 Server 的数据。</p><h2 id="server-可以提供什么" tabindex="-1">Server 可以提供什么 <a class="header-anchor" href="#server-可以提供什么" aria-label="Permalink to &quot;Server 可以提供什么&quot;">​</a></h2><p>MCP Server 常见的三类能力如下。</p><table tabindex="0"><thead><tr><th>能力</th><th>用途</th><th>示例</th></tr></thead><tbody><tr><td>Tools</td><td>可执行的动作，由模型选择调用</td><td><code>query_db</code>、<code>search_code</code>、<code>run_tests</code></td></tr><tr><td>Resources</td><td>可读取的上下文数据</td><td>文件、日志、表结构、配置、Schema</td></tr><tr><td>Prompts</td><td>可复用的提示模板或工作流入口</td><td><code>code_review</code>、<code>summarize_logs</code></td></tr></tbody></table><p>其中，Tools 是最常见的能力。每个工具包含名称、说明和 <code>inputSchema</code>；Schema 用于约束工具参数，帮助 Host 和 LLM 正确构造调用。</p><h2 id="一次工具调用如何发生" tabindex="-1">一次工具调用如何发生 <a class="header-anchor" href="#一次工具调用如何发生" aria-label="Permalink to &quot;一次工具调用如何发生&quot;">​</a></h2><p>下面的流程以“用户让 AI 查询数据库”为例。MCP 消息以 JSON-RPC 为基础传输。</p>',14)),(e(),r(p,null,{default:i(()=>[d(a,{id:"mermaid-147",class:"mermaid",graph:"sequenceDiagram%0A%20%20%20%20autonumber%0A%0A%20%20%20%20actor%20User%20as%20%E7%94%A8%E6%88%B7%0A%20%20%20%20participant%20Host%20as%20Host%20%2F%20AI%20%E5%BA%94%E7%94%A8%0A%20%20%20%20participant%20LLM%20as%20LLM%0A%20%20%20%20participant%20Client%20as%20MCP%20Client%0A%20%20%20%20participant%20Server%20as%20MCP%20Server%0A%0A%20%20%20%20User-%3E%3EHost%3A%20%E6%8F%90%E5%87%BA%E4%BB%BB%E5%8A%A1%20%2F%20%E9%97%AE%E9%A2%98%0A%20%20%20%20Host-%3E%3EClient%3A%20%E5%88%9B%E5%BB%BA%20Client%20%E5%B9%B6%E8%BF%9E%E6%8E%A5%20Server%0A%0A%20%20%20%20Client-%3E%3EServer%3A%20initialize%3Cbr%2F%3E%7B%20protocolVersion%2C%20capabilities%2C%20clientInfo%20%7D%0A%20%20%20%20Server--%3E%3EClient%3A%20result%3Cbr%2F%3E%7B%20protocolVersion%2C%20capabilities%2C%20serverInfo%20%7D%0A%20%20%20%20Client-%3E%3EServer%3A%20notifications%2Finitialized%0A%0A%20%20%20%20Note%20over%20Client%2CServer%3A%20%E5%88%9D%E5%A7%8B%E5%8C%96%E5%AE%8C%E6%88%90%EF%BC%8C%E8%BF%9B%E5%85%A5%E6%AD%A3%E5%B8%B8%E9%80%9A%E4%BF%A1%E9%98%B6%E6%AE%B5%0A%0A%20%20%20%20Client-%3E%3EServer%3A%20tools%2Flist%0A%20%20%20%20Server--%3E%3EClient%3A%20result%3Cbr%2F%3E%7B%20tools%3A%20%5B%7B%20name%2C%20description%2C%20inputSchema%20%7D%5D%20%7D%0A%20%20%20%20Client--%3E%3EHost%3A%20%E8%BF%94%E5%9B%9E%E5%8F%AF%E7%94%A8%E5%B7%A5%E5%85%B7%E5%88%97%E8%A1%A8%0A%0A%20%20%20%20Host-%3E%3ELLM%3A%20%E7%94%A8%E6%88%B7%E9%97%AE%E9%A2%98%20%2B%20%E5%B7%A5%E5%85%B7%E8%AF%B4%E6%98%8E%0A%20%20%20%20LLM--%3E%3EHost%3A%20%E9%80%89%E6%8B%A9%E5%B7%A5%E5%85%B7%20%2B%20%E7%94%9F%E6%88%90%E5%8F%82%E6%95%B0%0A%0A%20%20%20%20opt%20Host%20%E8%A6%81%E6%B1%82%E7%94%A8%E6%88%B7%E7%A1%AE%E8%AE%A4%0A%20%20%20%20%20%20%20%20Host-%3E%3EUser%3A%20%E5%B1%95%E7%A4%BA%E5%B7%A5%E5%85%B7%E5%92%8C%E5%8F%82%E6%95%B0%0A%20%20%20%20%20%20%20%20User--%3E%3EHost%3A%20approve%20%2F%20deny%0A%20%20%20%20end%0A%0A%20%20%20%20alt%20%E5%B7%B2%E5%85%81%E8%AE%B8%E6%88%96%E6%97%A0%E9%9C%80%E7%A1%AE%E8%AE%A4%0A%20%20%20%20%20%20%20%20Host-%3E%3EClient%3A%20%E8%AF%B7%E6%B1%82%E8%B0%83%E7%94%A8%E5%B7%A5%E5%85%B7%0A%20%20%20%20%20%20%20%20Client-%3E%3EServer%3A%20tools%2Fcall%3Cbr%2F%3E%7B%20name%2C%20arguments%20%7D%0A%0A%20%20%20%20%20%20%20%20opt%20%E9%95%BF%E4%BB%BB%E5%8A%A1%E8%BF%9B%E5%BA%A6%0A%20%20%20%20%20%20%20%20%20%20%20%20Server--%3E%3EClient%3A%20notifications%2Fprogress%0A%20%20%20%20%20%20%20%20%20%20%20%20Client--%3E%3EHost%3A%20%E6%9B%B4%E6%96%B0%E8%BF%9B%E5%BA%A6%0A%20%20%20%20%20%20%20%20end%0A%0A%20%20%20%20%20%20%20%20Server--%3E%3EClient%3A%20result%3Cbr%2F%3E%7B%20content%2C%20structuredContent%3F%2C%20isError%20%7D%0A%20%20%20%20%20%20%20%20Client--%3E%3EHost%3A%20%E8%BF%94%E5%9B%9E%E5%B7%A5%E5%85%B7%E7%BB%93%E6%9E%9C%0A%20%20%20%20%20%20%20%20Host-%3E%3ELLM%3A%20%E7%94%A8%E6%88%B7%E9%97%AE%E9%A2%98%20%2B%20%E5%B7%A5%E5%85%B7%E7%BB%93%E6%9E%9C%0A%20%20%20%20%20%20%20%20LLM--%3E%3EHost%3A%20%E7%94%9F%E6%88%90%E6%9C%80%E7%BB%88%E5%9B%9E%E7%AD%94%0A%20%20%20%20%20%20%20%20Host--%3E%3EUser%3A%20%E8%BF%94%E5%9B%9E%E7%AD%94%E6%A1%88%0A%20%20%20%20else%20%E7%94%A8%E6%88%B7%E6%8B%92%E7%BB%9D%0A%20%20%20%20%20%20%20%20Host--%3E%3EUser%3A%20%E5%8F%96%E6%B6%88%E8%B0%83%E7%94%A8%0A%20%20%20%20end%0A"})]),fallback:i(()=>[...t[0]||(t[0]=[E(" Loading... ",-1)])]),_:1})),t[2]||(t[2]=s(`<h3 id="_1-初始化与能力协商" tabindex="-1">1. 初始化与能力协商 <a class="header-anchor" href="#_1-初始化与能力协商" aria-label="Permalink to &quot;1. 初始化与能力协商&quot;">​</a></h3><p>Client 先发送 <code>initialize</code>，声明支持的协议版本、Client 能力和实现信息；Server 返回自己支持的协议版本、能力和服务信息。随后 Client 发送 <code>notifications/initialized</code>，表示初始化完成。</p><p>只有双方声明并协商成功的能力，才能在本次会话中使用。例如，Server 只有声明 <code>tools</code> 能力后，Client 才能调用 <code>tools/list</code> 和 <code>tools/call</code>。</p><h3 id="_2-发现可用工具" tabindex="-1">2. 发现可用工具 <a class="header-anchor" href="#_2-发现可用工具" aria-label="Permalink to &quot;2. 发现可用工具&quot;">​</a></h3><p>Client 通过 <code>tools/list</code> 获取工具清单。工具定义通常包括：</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;name&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;query_db&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;description&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;查询只读业务数据库&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;inputSchema&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;type&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;object&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;properties&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;sql&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: { </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;type&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;string&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    },</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;required&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;sql&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>Host 将工具说明提供给 LLM。LLM 负责把“查一下今天的订单数”这类自然语言需求转换为工具名和结构化参数；它不会直接连接数据库。</p><h3 id="_3-调用工具并使用结果" tabindex="-1">3. 调用工具并使用结果 <a class="header-anchor" href="#_3-调用工具并使用结果" aria-label="Permalink to &quot;3. 调用工具并使用结果&quot;">​</a></h3><p>Host 把 LLM 的选择交给 Client，Client 发送 <code>tools/call</code>：</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;name&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;query_db&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;arguments&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;sql&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;SELECT COUNT(*) AS order_count FROM orders WHERE created_at &gt;= CURRENT_DATE&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>Server 执行操作并返回 <code>content</code>，也可以同时返回适合程序处理的 <code>structuredContent</code>。对于耗时任务，Server 可通过 <code>notifications/progress</code> 报告进度。Host 再将结果交给 LLM，由 LLM 解释结果并回复用户。</p><h2 id="权限与安全" tabindex="-1">权限与安全 <a class="header-anchor" href="#权限与安全" aria-label="Permalink to &quot;权限与安全&quot;">​</a></h2><p>MCP 解决的是“标准化连接”，不等于自动获得安全保障。实践中应把安全边界放在 Host 和 Server 两端：</p><ul><li>Host 应向用户清晰展示正在使用的工具；对写入、删除、执行命令、发送消息等高风险操作进行确认。</li><li>Server 应按最小权限运行，例如数据库 Server 使用只读账号，文件系统 Server 限制可访问目录。</li><li>工具参数和工具返回内容都应视为不可信输入；避免把敏感数据、提示注入内容或未经验证的命令直接传递到下游系统。</li><li>为调用设置超时、审计日志和可撤销机制，避免故障或误操作无限扩大影响。</li></ul><p>需要注意：用户确认属于 Host 的交互与安全策略，MCP 协议本身不规定必须采用哪一种确认界面；但官方规范建议为工具调用保留人工拒绝的能力。</p><h2 id="工具列表变化与连接结束" tabindex="-1">工具列表变化与连接结束 <a class="header-anchor" href="#工具列表变化与连接结束" aria-label="Permalink to &quot;工具列表变化与连接结束&quot;">​</a></h2><p>Server 如果在能力协商中声明了 <code>tools.listChanged</code>，工具列表发生变化时可以发送 <code>notifications/tools/list_changed</code>。Client 随后重新调用 <code>tools/list</code>，让 Host 获得最新能力。</p><p>会话结束时，通常由 Client 关闭底层连接或子进程。MCP 没有定义独立的 <code>close</code> 协议消息：<code>stdio</code> 传输通过关闭子进程输入和进程退出结束，HTTP 传输通过关闭相关连接结束。</p><h2 id="小结" tabindex="-1">小结 <a class="header-anchor" href="#小结" aria-label="Permalink to &quot;小结&quot;">​</a></h2><p>MCP 的价值不在于替代 LLM，而在于把 AI 应用与外部工具、数据和工作流解耦：</p><ol><li>Server 以统一协议暴露能力。</li><li>Host 负责连接、权限、会话和上下文编排。</li><li>LLM 根据任务选择工具，并把结果组织为用户可理解的回答。</li></ol><p>这种分工使一个 AI 应用能够组合多个独立 Server，同时保留清晰的权限边界和可控的工具调用过程。</p><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ul><li><a href="https://modelcontextprotocol.io/specification/2025-11-25/architecture" target="_blank" rel="noreferrer">MCP 架构说明</a></li><li><a href="https://modelcontextprotocol.io/specification/2025-11-25/basic/lifecycle" target="_blank" rel="noreferrer">MCP 连接生命周期</a></li><li><a href="https://modelcontextprotocol.io/specification/2025-11-25/server/tools" target="_blank" rel="noreferrer">MCP Tools 规范</a></li></ul>`,24))])}const b=o(c,[["render",A]]);export{q as __pageData,b as default};
